@@ -171,0 +171,19 @@
+// Use this instead of sizeof() if you want your expression not to be of type size_t
+template <typename T>
+constexpr auto sizeof_auto() {
+  constexpr size_t N = sizeof(T);
+
+  using unsigned_auto =
+    std::conditional_t<N <= std::numeric_limits<uint8_t>::max(), uint8_t,
+      std::conditional_t<N <= std::numeric_limits<uint16_t>::max(), uint16_t,
+        std::conditional_t<N <= std::numeric_limits<uint32_t>::max(), uint32_t, uint64_t>>>;
+
+  return static_cast<unsigned_auto>(N);
+}
+
+// Use this instead of sizeof() if you want your expression not to be of type size_t
+template <typename T>
+constexpr auto sizeof_auto(const T& t) {
+  return sizeof_auto<T>();
+}
+

@@ -324,0 +324,33 @@
+
+struct NoCopy {
+  int x;
+  NONCOPYABLE(NoCopy);
+};
+
+TEST(globalDefinitions, sizeof_auto) {
+  char x = 5;
+  char& y = x;
+  char* z = &x;
+  EXPECT_EQ(sizeof_auto(x), sizeof(x));
+  EXPECT_EQ(sizeof_auto(y), sizeof(y));
+  EXPECT_EQ(sizeof_auto(z), sizeof(z));
+
+  NoCopy nc{0};
+  sizeof_auto(nc);
+
+  static_assert(sizeof_auto<char[std::numeric_limits<uint8_t>::max()]>()  == std::numeric_limits<uint8_t>::max());
+  static_assert(sizeof_auto<char[std::numeric_limits<uint16_t>::max()]>()  == std::numeric_limits<uint16_t>::max());
+  static_assert(sizeof_auto<char[std::numeric_limits<uint32_t>::max()]>()  == std::numeric_limits<uint32_t>::max());
+#ifdef  _LP64
+  static_assert(sizeof_auto<char[std::numeric_limits<uint32_t>::max()+1LL]>()  == std::numeric_limits<uint32_t>::max()+1LL);
+#endif
+
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint8_t>::max()]>())  == sizeof(uint8_t));
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint8_t>::max()+1LL]>())  == sizeof(uint16_t));
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint16_t>::max()]>()) == sizeof(uint16_t));
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint16_t>::max()+1LL]>()) == sizeof(uint32_t));
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint32_t>::max()]>()) == sizeof(uint32_t));
+#ifdef  _LP64
+  static_assert(sizeof(sizeof_auto<char[std::numeric_limits<uint32_t>::max()+1LL]>()) == sizeof(uint64_t));
+#endif
+}
